import React, { useEffect, useMemo, useRef, useState } from "react";
import {
    Download,
    Link as LinkIcon,
    ListChecks,
    IdCard,
    FileSpreadsheet,
    UploadCloud,
} from "lucide-react";
import * as XLSX from "xlsx";
import "./SiparisOlustur.css";
import supabase from "../supabaseClient";

const DATA_TABLE = "Siparisler";

/** UI başlıkları */
const HEADERS = [
    "Vkn",
    "Proje",
    "Sipariş Tarihi",
    "Yükleme Tarihi",
    "Teslim Tarihi",
    "Müşteri Sipariş No",
    "Müşteri Referans No",
    "İstenilen Araç Tipi",
    "Açıklama",
    "Yükleme Firması Adı",
    "Alıcı Firma Cari Adı",
    "Teslim Firma Adres Adı",
    "İrsaliye No",
    "İrsaliye Miktarı",
    "Ürün",
    "Kap Adet",
    "Ambalaj  Tipi", // çift boşluk var
    "Brüt KG",
    "M3",
    "Desi",
];

const REQUIRED_EXPORT_HEADERS = [
    "Sipariş Tarihi",
    "Müşteri Sipariş No",
    "İstenilen Araç Tipi",
    "Açıklama",
    "Yükleme Firması Adı",
    "Alıcı Firma Cari Adı",
    "Teslim Firma Adres Adı",
];

/** Supabase → UI eşleme */
const FIELD_OVERLAY_MAP = {
    vkn: "Vkn",
    proje_id: "Proje", // proje_id değeri buraya yazılacak
    Musteri_Siparis_No: "Müşteri Sipariş No",
    Alici_Firma_Cari_Unvani: "Alıcı Firma Cari Adı",
    Urun: "Ürün",
    Kap_Adet: "Kap Adet",
    Ambalaj_Tipi: "Ambalaj  Tipi",
    Brut_KG: "Brüt KG",
    Yukleme_Firma_Adres_Adi: "Yükleme Firması Adı",
};
const SELECT_COLS = Object.keys(FIELD_OVERLAY_MAP).join(", ");

const emptyRow = () =>
    HEADERS.reduce((acc, key) => ({ ...acc, [key]: "" }), {});
const normalize = (s) => String(s ?? "").replace(/\s+/g, " ").trim();
const sortTr = (a, b) =>
    String(a).localeCompare(String(b), "tr", { sensitivity: "base" });

/** Excel + Proje satırlarını birleştir */
function mergeRows(excelRows, projectRows) {
    const maxLen = Math.max(excelRows.length, projectRows.length);
    return Array.from({ length: maxLen }).map((_, i) => {
        const base = excelRows[i] ? { ...excelRows[i] } : emptyRow();
        const rec = projectRows[i];
        if (rec) {
            Object.entries(FIELD_OVERLAY_MAP).forEach(([src, dest]) => {
                base[dest] = src === "proje_id"
                    ? String(rec.proje_id ?? "")
                    : normalize(rec[src] ?? base[dest]);
            });
        }
        return base;
    });
}

export default function SiparisOlustur() {
    const [projeAdi, setProjeAdi] = useState("");
    const [excelRows, setExcelRows] = useState([]);
    const [projectRows, setProjectRows] = useState([]);
    const [rows, setRows] = useState([]);

    const [projects, setProjects] = useState([]); // {id, name}
    const [projectsLoading, setProjectsLoading] = useState(false);
    const [projectsError, setProjectsError] = useState("");

    const [error, setError] = useState("");
    const [lastFile, setLastFile] = useState(null);
    const [dragActive, setDragActive] = useState(false);
    const fileInputRef = useRef(null);

    const columns = useMemo(() => HEADERS, []);

    /** Projeler listesi */
    useEffect(() => {
        const fetchProjects = async () => {
            setProjectsLoading(true);
            try {
                const { data, error } = await supabase
                    .from("Projeler")
                    .select("id, Proje_Adi");
                if (error) throw error;
                const list = (data || [])
                    .map((x) => ({ id: x.id, name: (x.Proje_Adi ?? "").trim() }))
                    .filter((x) => x.id && x.name.length > 0)
                    .sort((a, b) => sortTr(a.name, b.name));
                setProjects(list);
            } catch (e) {
                setProjectsError(e.message);
            } finally {
                setProjectsLoading(false);
            }
        };
        fetchProjects();
    }, []);

    /** Proje seçildiğinde supabase’ten satır çek */
    useEffect(() => {
        const fetchProjectRows = async () => {
            if (!projeAdi) {
                setProjectRows([]);
                return;
            }
            const selected = projects.find((p) => p.name === projeAdi);
            if (!selected) return;
            try {
                const { data, error } = await supabase
                    .from(DATA_TABLE)
                    .select(SELECT_COLS)
                    .eq("proje_id", selected.id);
                if (error) throw error;
                setProjectRows(data || []);
            } catch (e) {
                setProjectRows([]);
                setError(e.message);
            }
        };
        fetchProjectRows();
    }, [projeAdi, projects]);

    /** Excel veya proje satırları değişince birleştir */
    useEffect(() => {
        setRows(mergeRows(excelRows, projectRows));
    }, [excelRows, projectRows]);

    /** Excel içe aktar */
    const parseExcel = async (file) => {
        setError("");
        try {
            if (!projeAdi) throw new Error("Önce proje seçmelisiniz.");
            const buf = await file.arrayBuffer();
            const wb = XLSX.read(buf, { type: "array" });
            const ws = wb.Sheets[wb.SheetNames[0]];
            const aoa = XLSX.utils.sheet_to_json(ws, { header: 1, defval: "" });
            const [rawHeaders, ...body] = aoa;
            const headerIndexMap = {};
            HEADERS.forEach((h) => {
                const idx = rawHeaders.findIndex((x) => normalize(x) === normalize(h));
                headerIndexMap[h] = idx;
            });
            const missing = REQUIRED_EXPORT_HEADERS.filter(
                (h) => headerIndexMap[h] === -1
            );
            if (missing.length)
                throw new Error(`Eksik başlık: ${missing.join(", ")}`);
            const parsedRows = body
                .filter((row) => row.some((c) => normalize(c) !== ""))
                .map((row) => {
                    const obj = {};
                    HEADERS.forEach((h) => {
                        const idx = headerIndexMap[h];
                        obj[h] = idx >= 0 ? normalize(row[idx]) : "";
                    });
                    return obj;
                });
            setExcelRows(parsedRows);
            setLastFile(file);
        } catch (e) {
            setExcelRows([]);
            setError(e.message);
        }
    };

    const onDrop = (e) => {
        e.preventDefault();
        setDragActive(false);
        const f = e.dataTransfer.files?.[0];
        if (f) parseExcel(f);
    };
    const onDragOver = (e) => { e.preventDefault(); setDragActive(true); };
    const onDragLeave = () => setDragActive(false);
    const pickFile = () => fileInputRef.current?.click();
    const onFileChange = (e) => { const f = e.target.files?.[0]; if (f) parseExcel(f); e.target.value = ""; };

    return (
        <div className="so-page">
            <div className="so-header">
                <h1 className="so-title">Sipariş Oluştur</h1>
            </div>

            {/* Proje seçimi */}
            <div className="so-card">
                <label className="so-label">Proje Adı *</label>
                <select className="so-input" value={projeAdi} onChange={(e) => setProjeAdi(e.target.value)}>
                    <option value="">Seçiniz</option>
                    {projects.map((p) => <option key={p.id} value={p.name}>{p.name}</option>)}
                </select>
            </div>

            {/* Tablo */}
            <div className="so-table-card">
                <div className="so-table-header">
                    <ListChecks size={18} /> <span>Şablon</span>
                </div>
                <div className="so-table-wrap">
                    <table className="so-table">
                        <thead>
                            <tr>
                                <th>#</th>
                                {columns.map((c) => <th key={c}>{c}</th>)}
                            </tr>
                        </thead>
                        <tbody>
                            {rows.length === 0 ? (
                                <tr>
                                    <td colSpan={columns.length + 1}>
                                        <div className={`so-drop-in-table ${dragActive ? "active" : ""}`}
                                            onDrop={onDrop} onDragOver={onDragOver} onDragLeave={onDragLeave}
                                            onClick={pickFile}>
                                            <UploadCloud size={30} />
                                            <div>Excel sürükleyip bırakın ya da tıklayın</div>
                                            <input ref={fileInputRef} type="file" accept=".xlsx,.xls" hidden onChange={onFileChange} />
                                        </div>
                                    </td>
                                </tr>
                            ) : rows.map((row, i) => (
                                <tr key={i}>
                                    <td>{i + 1}</td>
                                    {columns.map((col) => <td key={col}>{row[col]}</td>)}
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
                {error && <p className="so-error">{error}</p>}
                {lastFile && <p className="so-help">Yüklü: {lastFile.name}</p>}
            </div>
        </div>
    );
}
